import React, { useEffect, useState } from "react";
import "./RepoPreview.css";

export default function RepoPreview() {
  const [repo, setRepo] = useState(null);
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const handler = (e) => {
      setRepo(e.detail);
      setIsOpen(true);
    };
    window.addEventListener("openRepoPreview", handler);
    return () => window.removeEventListener("openRepoPreview", handler);
  }, []);

  if (!isOpen || !repo) return null;

  return (
    <div className="repo-preview-overlay" onClick={() => setIsOpen(false)}>
      <div className="repo-preview" onClick={e => e.stopPropagation()}>
        <header className="repo-preview-header">
          <h2>{repo.name}</h2>
          <img src={repo.ownerAvatar} alt={repo.owner} className="repo-owner-avatar" />
          <span>{repo.owner}</span>
          <button onClick={() => setIsOpen(false)} className="close-button">×</button>
        </header>

        <section className="repo-preview-meta">
          <p>⭐ Stars: {repo.stars}</p>
          <p>🍴 Forks: {repo.forks}</p>
          <p>🐛 Open issues: {repo.openIssues}</p>
          <p>🔀 Pull requests: {repo.pullRequests}</p>
          <p>License: {repo.license}</p>
          <p>Visibility: {repo.visibility}</p>
          <p>Status: {repo.status}</p>
          {repo.languages.length > 0 && (
            <p>Languages: {repo.languages.join(", ")}</p>
          )}
        </section>

        <section className="repo-preview-readme">
          <h3>README</h3>
          <div className="readme-content">
            <pre>{repo.readme || "README not found"}</pre>
          </div>
        </section>

        <section className="repo-preview-actions">
          <button onClick={() => navigator.clipboard.writeText(repo.cloneUrl)}>Copy git clone</button>
          {repo.documentationLink && <a href={repo.documentationLink} target="_blank" rel="noopener noreferrer">Wiki / Docs</a>}
          {repo.liveDemoLink && <a href={repo.liveDemoLink} target="_blank" rel="noopener noreferrer">Live Demo</a>}
        </section>
      </div>
    </div>
  );
}
